/// Testfixture (--dev) option list: production + SQLITE_DEBUG + SQLITE_TEST.
/// The three extra entries (DEBUG, NEED_ERR_NAME, TEST) keep the array A-Z
/// sorted. 59 entries.
const opts_tf = [_][*:0]const u8{
    "ATOMIC_INTRINSICS=1",
    compiler_opt,
    "DEBUG",
    "DEFAULT_AUTOVACUUM",
    "DEFAULT_CACHE_SIZE=-2000",
    "DEFAULT_FILE_FORMAT=4",
    "DEFAULT_JOURNAL_SIZE_LIMIT=-1",
    "DEFAULT_MMAP_SIZE=0",
