/// Comptime-selected table. Testfixture (--dev) iff both DEBUG and TEST are set
/// (build.zig sets `sqlite_debug` and `sqlite_test` together via -Dtestfixture);
/// otherwise the production list.
const azCompileOpt = if (config.sqlite_debug and config.sqlite_test) &opts_tf else &opts_prod;

/// C ABI: `const char **sqlite3CompileOptions(int *pnOpt)`.
/// Writes the option count to `pnOpt` and returns the (A-Z sorted) array of
/// option-name strings. The returned pointer is to static storage.
export fn sqlite3CompileOptions(pnOpt: *c_int) callconv(.c) ?[*]const ?[*:0]const u8 {
    pnOpt.* = @intCast(azCompileOpt.len);
    // [N][*:0]const u8 -> [*]const ?[*:0]const u8 : same representation
    // (array of non-null string pointers, viewed as nullable string pointers).
    return @ptrCast(azCompileOpt);
}
